start_time = datetime.datetime.now()

engine = None

# -----------------------------------------------------------------------------
# Run-output capture / clipboard package helpers
# -----------------------------------------------------------------------------
RUN_OUTPUT_LINES = []
LLM_DIAGNOSTIC_TEXT = ''
_ORIGINAL_PRINT = builtins.print


def _stringify_print_args(*args, sep=' '):
    return sep.join(str(arg) for arg in args)


def _capture_print(*args, **kwargs):
    """
    Replacement print() that preserves normal console output while capturing every
    printed line for the final LLM clipboard package.
    """
    sep = kwargs.get('sep', ' ')
    try:
        RUN_OUTPUT_LINES.append(_stringify_print_args(*args, sep=sep))
    except Exception:
        pass
    return _ORIGINAL_PRINT(*args, **kwargs)


builtins.print = _capture_print

def _progress(message, **metrics):
    """
    Prints a compact progress message with current timestamp, elapsed minutes,
    and optional row-count / phase metrics.
    """
    now = datetime.datetime.now()
    elapsed_min = (now - start_time).total_seconds() / 60

    metric_parts = []
    for key, value in metrics.items():
        if value is None:
            continue
        try:
            if isinstance(value, (int, np.integer)):
                value = f"{int(value):,}"
            elif isinstance(value, (float, np.floating)):
                value = f"{float(value):,.2f}"
        except Exception:
            pass
        metric_parts.append(f"{key}={value}")

    metric_text = " | " + " | ".join(metric_parts) if metric_parts else ""
    print(f"[{now:%Y-%m-%d %H:%M:%S}] +{elapsed_min:.2f} min | {message}{metric_text}", flush=True)


def _row_count(df):
    try:
        return len(df)
    except Exception:
        return None


def _fetch_sql_batch_as_dataframe(engine, sql_text):
    """
    Executes a SQL Server batch and returns the first resultset with columns.
    This supports temp tables / inserts before the final SELECT.
    """
    conn = engine.raw_connection()
    try:
        cursor = conn.cursor()
        cursor.execute(sql_text)
        while cursor.description is None:
            if not cursor.nextset():
                return pd.DataFrame()
        columns = [col[0] for col in cursor.description]
        rows = cursor.fetchall()
        return pd.DataFrame.from_records(rows, columns=columns)
    finally:
        conn.close()


def _format_dataframe_for_llm(df, max_rows=500):
    if df is None or df.empty:
        return '<no rows returned>'
    out = df.copy()
    if len(out) > max_rows:
        out = out.head(max_rows).copy()
        trunc_msg = f"\n<TRUNCATED: showing first {max_rows:,} of {len(df):,} rows>"
    else:
        trunc_msg = ''
    return out.to_csv(index=False, sep='\t') + trunc_msg


def _build_v4_post_write_diagnostic_sql(net_grp='ANA_01F'):
    """
    Returns a one-resultset diagnostic pack intended for LLM review after the
    V4 output table has been written. Keep this query concise enough to fit in
    clipboard output but broad enough to catch the common failure modes.
    """
    safe_net_grp = str(net_grp).replace("'", "''")
    return f"""
SET NOCOUNT ON;

DECLARE @NetGrp varchar(100) = '{safe_net_grp}';

IF OBJECT_ID('tempdb..#Diagnostics') IS NOT NULL DROP TABLE #Diagnostics;
IF OBJECT_ID('tempdb..#IssueHistoryMO') IS NOT NULL DROP TABLE #IssueHistoryMO;
IF OBJECT_ID('tempdb..#OriginalMO') IS NOT NULL DROP TABLE #OriginalMO;
IF OBJECT_ID('tempdb..#AssignedMO') IS NOT NULL DROP TABLE #AssignedMO;
IF OBJECT_ID('tempdb..#OrphanMO') IS NOT NULL DROP TABLE #OrphanMO;
IF OBJECT_ID('tempdb..#CombinedMO') IS NOT NULL DROP TABLE #CombinedMO;
IF OBJECT_ID('tempdb..#FinalGrain') IS NOT NULL DROP TABLE #FinalGrain;
IF OBJECT_ID('tempdb..#CoveredParentDesc') IS NOT NULL DROP TABLE #CoveredParentDesc;
IF OBJECT_ID('tempdb..#MOParentDesc') IS NOT NULL DROP TABLE #MOParentDesc;
IF OBJECT_ID('tempdb..#SeedTopLevel') IS NOT NULL DROP TABLE #SeedTopLevel;

CREATE TABLE #Diagnostics
(
      DiagnosticNo int
    , DiagnosticName varchar(200)
    , Severity varchar(20)
    , FailureKey varchar(500) NULL
    , RES_ID varchar(100) NULL
    , RES_LN_NO int NULL
    , BOM_LVL int NULL
    , MRP_NEED_DATE datetime NULL
    , ASY_ORD varchar(100) NULL
    , COMP_PART_KEY decimal(18, 0) NULL
    , COMP_NET_GRP_ID varchar(100) NULL
    , ORD_ID varchar(100) NULL
    , DBG_Explosion_Source varchar(100) NULL
    , DBG_Matched_MO_ID varchar(100) NULL
    , RowCnt int NULL
    , RequiredQty decimal(38, 8) NULL
    , AvailableQty decimal(38, 8) NULL
    , ExtraQty decimal(38, 8) NULL
    , OriginalQty decimal(38, 8) NULL
    , AssignedQty decimal(38, 8) NULL
    , OrphanQty decimal(38, 8) NULL
    , ExpectedQty decimal(38, 8) NULL
    , ResidualDelta decimal(38, 8) NULL
    , DiagnosticStatus varchar(300)
    , Notes varchar(2000)
);

-- 0. Source profile
INSERT INTO #Diagnostics
(
      DiagnosticNo, DiagnosticName, Severity, FailureKey, COMP_NET_GRP_ID,
      DBG_Explosion_Source, RowCnt, RequiredQty, AvailableQty, DiagnosticStatus, Notes
)
SELECT
      0
    , 'Source profile'
    , 'INFO'
    , CONCAT('SRC=', ISNULL(DBG_Explosion_Source, '<BLANK>'))
    , COMP_NET_GRP_ID
    , DBG_Explosion_Source
    , COUNT(*)
    , SUM(CAST(COALESCE([Line Qty. Required], 0) AS decimal(38, 8)))
    , SUM(CAST(COALESCE([Line Qty. Available], 0) AS decimal(38, 8)))
    , 'Profile only'
    , 'Final row count and qty by V4 source.'
FROM MPM_DWH.dbo.MRP_V4
WHERE COMP_NET_GRP_ID = @NetGrp
GROUP BY COMP_NET_GRP_ID, DBG_Explosion_Source;

-- 1. Blank source rows
INSERT INTO #Diagnostics
(
      DiagnosticNo, DiagnosticName, Severity, FailureKey, RES_ID, RES_LN_NO, BOM_LVL,
      MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY, COMP_NET_GRP_ID, ORD_ID,
      DBG_Explosion_Source, DBG_Matched_MO_ID, RowCnt, RequiredQty, AvailableQty,
      DiagnosticStatus, Notes
)
SELECT
      1
    , 'Blank DBG_Explosion_Source'
    , 'FAIL'
    , CONCAT('RES=', RES_ID, '|LN=', RES_LN_NO, '|LVL=', BOM_LVL, '|PART=', COMP_PART_KEY)
    , RES_ID, RES_LN_NO, BOM_LVL, MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY, COMP_NET_GRP_ID
    , ORD_ID, DBG_Explosion_Source, DBG_Matched_MO_ID
    , COUNT(*)
    , SUM(CAST(COALESCE([Line Qty. Required], 0) AS decimal(38, 8)))
    , SUM(CAST(COALESCE([Line Qty. Available], 0) AS decimal(38, 8)))
    , 'Blank source should be labeled'
    , 'Expected labeled source such as SHORT_MAKE, MBOM, MO_RQMT, COVERED_*, ORPHAN_SUPPLY.'
FROM MPM_DWH.dbo.MRP_V4
WHERE COMP_NET_GRP_ID = @NetGrp
  AND ISNULL(LTRIM(RTRIM(DBG_Explosion_Source)), '') = ''
GROUP BY RES_ID, RES_LN_NO, BOM_LVL, MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY,
         COMP_NET_GRP_ID, ORD_ID, DBG_Explosion_Source, DBG_Matched_MO_ID;

-- 2. Available > required, excluding valid exceptions
INSERT INTO #Diagnostics
(
      DiagnosticNo, DiagnosticName, Severity, FailureKey, RES_ID, RES_LN_NO, BOM_LVL,
      MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY, COMP_NET_GRP_ID, ORD_ID,
      DBG_Explosion_Source, DBG_Matched_MO_ID, RowCnt, RequiredQty, AvailableQty, ExtraQty,
      DiagnosticStatus, Notes
)
SELECT TOP (200)
      2
    , 'Available greater than required'
    , 'FAIL'
    , CONCAT('RES=', ISNULL(RES_ID, '<NULL>'), '|LN=', ISNULL(CONVERT(varchar(20), RES_LN_NO), '<NULL>'), '|PART=', COMP_PART_KEY, '|ORD=', ISNULL(ORD_ID, '<NULL>'))
    , RES_ID, RES_LN_NO, BOM_LVL, MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY, COMP_NET_GRP_ID
    , ORD_ID, DBG_Explosion_Source, DBG_Matched_MO_ID
    , 1
    , CAST(COALESCE([Line Qty. Required], 0) AS decimal(38, 8))
    , CAST(COALESCE([Line Qty. Available], 0) AS decimal(38, 8))
    , CAST(COALESCE([Line Qty. Available], 0) - COALESCE([Line Qty. Required], 0) AS decimal(38, 8))
    , 'Normal demand row has available qty above required qty'
    , 'Allowed exceptions: ORPHAN_SUPPLY and MO_RQMT_ZERO_REQ_ISSUED.'
FROM MPM_DWH.dbo.MRP_V4
WHERE COMP_NET_GRP_ID = @NetGrp
  AND ISNULL(DBG_Explosion_Source, '') NOT IN ('ORPHAN_SUPPLY', 'MO_RQMT_ZERO_REQ_ISSUED')
  AND COALESCE([Line Qty. Available], 0) > COALESCE([Line Qty. Required], 0) + 0.0001
ORDER BY COALESCE([Line Qty. Available], 0) - COALESCE([Line Qty. Required], 0) DESC;

-- 3. Negative quantity checks
INSERT INTO #Diagnostics
(
      DiagnosticNo, DiagnosticName, Severity, FailureKey, RES_ID, RES_LN_NO, BOM_LVL,
      MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY, COMP_NET_GRP_ID, ORD_ID,
      DBG_Explosion_Source, RowCnt, RequiredQty, AvailableQty, DiagnosticStatus, Notes
)
SELECT TOP (200)
      3
    , 'Negative quantity'
    , 'FAIL'
    , CONCAT('RES=', ISNULL(RES_ID, '<NULL>'), '|LN=', ISNULL(CONVERT(varchar(20), RES_LN_NO), '<NULL>'), '|PART=', ISNULL(CONVERT(varchar(50), COMP_PART_KEY), '<NULL>'))
    , RES_ID, RES_LN_NO, BOM_LVL, MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY, COMP_NET_GRP_ID
    , ORD_ID, DBG_Explosion_Source, 1
    , CAST(COALESCE([Line Qty. Required], 0) AS decimal(38, 8))
    , CAST(COALESCE([Line Qty. Available], 0) AS decimal(38, 8))
    , 'Negative required or available qty'
    , 'Final output should not have negative quantities.'
FROM MPM_DWH.dbo.MRP_V4
WHERE COMP_NET_GRP_ID = @NetGrp
  AND (COALESCE([Line Qty. Required], 0) < -0.0001 OR COALESCE([Line Qty. Available], 0) < -0.0001);

-- 4. Source-specific quantity rules
INSERT INTO #Diagnostics
(
      DiagnosticNo, DiagnosticName, Severity, FailureKey, DBG_Explosion_Source, RowCnt,
      RequiredQty, AvailableQty, ExtraQty, DiagnosticStatus, Notes
)
SELECT
      4
    , 'Covered source quantity rule'
    , 'FAIL'
    , CONCAT('SRC=', ISNULL(DBG_Explosion_Source, '<BLANK>'), '|RULE=covered req should equal avail')
    , DBG_Explosion_Source
    , COUNT(*)
    , SUM(CAST(COALESCE([Line Qty. Required], 0) AS decimal(38, 8)))
    , SUM(CAST(COALESCE([Line Qty. Available], 0) AS decimal(38, 8)))
    , SUM(CAST(COALESCE([Line Qty. Available], 0) - COALESCE([Line Qty. Required], 0) AS decimal(38, 8)))
    , 'Covered source total required does not equal available'
    , 'COVERED_* / MO_MATCHED_PARENT / MO_RQMT_COVERED should normally be fully covered.'
FROM MPM_DWH.dbo.MRP_V4
WHERE COMP_NET_GRP_ID = @NetGrp
  AND ISNULL(DBG_Explosion_Source, '') IN
      ('COVERED_ISSUED', 'COVERED_HARD_PEGGED_INV', 'COVERED_GENERAL_INV', 'COVERED_PO', 'COVERED_PR', 'COVERED_PLO', 'MO_MATCHED_PARENT', 'MO_RQMT_COVERED')
GROUP BY DBG_Explosion_Source
HAVING ABS(SUM(CAST(COALESCE([Line Qty. Available], 0) AS decimal(38, 8)))
         - SUM(CAST(COALESCE([Line Qty. Required], 0) AS decimal(38, 8)))) > 0.0001;

INSERT INTO #Diagnostics
(
      DiagnosticNo, DiagnosticName, Severity, FailureKey, DBG_Explosion_Source, RowCnt,
      RequiredQty, AvailableQty, DiagnosticStatus, Notes
)
SELECT
      4
    , 'Short source quantity rule'
    , 'FAIL'
    , CONCAT('SRC=', ISNULL(DBG_Explosion_Source, '<BLANK>'), '|RULE=short rows should have zero avail')
    , DBG_Explosion_Source
    , COUNT(*)
    , SUM(CAST(COALESCE([Line Qty. Required], 0) AS decimal(38, 8)))
    , SUM(CAST(COALESCE([Line Qty. Available], 0) AS decimal(38, 8)))
    , 'Short/uncovered source has available qty'
    , 'MBOM / MO_RQMT / SHORT_MAKE / MBOM_FALLBACK_FROM_MO should normally have zero available qty.'
FROM MPM_DWH.dbo.MRP_V4
WHERE COMP_NET_GRP_ID = @NetGrp
  AND ISNULL(DBG_Explosion_Source, '') IN ('MBOM', 'MO_RQMT', 'SHORT_MAKE', 'MBOM_FALLBACK_FROM_MO')
GROUP BY DBG_Explosion_Source
HAVING ABS(SUM(CAST(COALESCE([Line Qty. Available], 0) AS decimal(38, 8)))) > 0.0001;

-- 5. Quantity-fragment candidates
SELECT
      RES_PART_KEY, RES_ID, RES_LN_NO, RES_PART_QTY, RES_NEED_DT, RES_NET_GRP_ID,
      BOM_LVL, MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY, COMP_NET_GRP_ID, COMP_QTY,
      REC_STATUS, Demand_Status, ORD_ID, ORD_STATUS_CD, NEED_DT, ORD_QTY,
      DBG_Explosion_Source, DBG_Matched_MO_ID,
      COUNT(*) AS RowCnt,
      COUNT(DISTINCT ISNULL(PATH_STRING, '<NULL>')) AS DistinctHiddenPathCnt,
      SUM(CAST(COALESCE([Line Qty. Required], 0) AS decimal(38, 8))) AS TotalRequiredQty,
      SUM(CAST(COALESCE([Line Qty. Available], 0) AS decimal(38, 8))) AS TotalAvailableQty
INTO #FinalGrain
FROM MPM_DWH.dbo.MRP_V4
WHERE COMP_NET_GRP_ID = @NetGrp
GROUP BY RES_PART_KEY, RES_ID, RES_LN_NO, RES_PART_QTY, RES_NEED_DT, RES_NET_GRP_ID,
         BOM_LVL, MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY, COMP_NET_GRP_ID, COMP_QTY,
         REC_STATUS, Demand_Status, ORD_ID, ORD_STATUS_CD, NEED_DT, ORD_QTY,
         DBG_Explosion_Source, DBG_Matched_MO_ID;

INSERT INTO #Diagnostics
(
      DiagnosticNo, DiagnosticName, Severity, FailureKey, RES_ID, RES_LN_NO, BOM_LVL,
      MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY, COMP_NET_GRP_ID, ORD_ID,
      DBG_Explosion_Source, DBG_Matched_MO_ID, RowCnt, RequiredQty, AvailableQty,
      DiagnosticStatus, Notes
)
SELECT TOP (200)
      5
    , 'Quantity-fragment candidate'
    , 'FAIL'
    , CONCAT('RES=', RES_ID, '|LN=', RES_LN_NO, '|LVL=', BOM_LVL, '|PART=', COMP_PART_KEY, '|SRC=', ISNULL(DBG_Explosion_Source, '<NULL>'))
    , RES_ID, RES_LN_NO, BOM_LVL, MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY, COMP_NET_GRP_ID
    , ORD_ID, DBG_Explosion_Source, DBG_Matched_MO_ID
    , RowCnt, TotalRequiredQty, TotalAvailableQty
    , 'Same final reporting grain still has multiple rows'
    , 'Expected blank after explicit final reporting-grain collapse.'
FROM #FinalGrain
WHERE RowCnt > 1 AND DistinctHiddenPathCnt = 1
ORDER BY RowCnt DESC, TotalRequiredQty DESC, RES_ID, RES_LN_NO, BOM_LVL, COMP_PART_KEY;

-- 6. Orphan supply scope and required-qty rules
INSERT INTO #Diagnostics
(
      DiagnosticNo, DiagnosticName, Severity, FailureKey, COMP_NET_GRP_ID, DBG_Explosion_Source,
      RowCnt, RequiredQty, AvailableQty, DiagnosticStatus, Notes
)
SELECT
      6
    , 'Orphan supply outside target net group'
    , 'FAIL'
    , CONCAT('NG=', ISNULL(COMP_NET_GRP_ID, '<NULL>'))
    , COMP_NET_GRP_ID, DBG_Explosion_Source, COUNT(*)
    , SUM(CAST(COALESCE([Line Qty. Required], 0) AS decimal(38, 8)))
    , SUM(CAST(COALESCE([Line Qty. Available], 0) AS decimal(38, 8)))
    , 'Orphan supply outside target net group'
    , 'For one-net-group validation, orphan supply should only be in @NetGrp.'
FROM MPM_DWH.dbo.MRP_V4
WHERE DBG_Explosion_Source = 'ORPHAN_SUPPLY'
  AND ISNULL(COMP_NET_GRP_ID, '<NULL>') <> @NetGrp
GROUP BY COMP_NET_GRP_ID, DBG_Explosion_Source;

INSERT INTO #Diagnostics
(
      DiagnosticNo, DiagnosticName, Severity, FailureKey, COMP_NET_GRP_ID, DBG_Explosion_Source,
      RowCnt, RequiredQty, AvailableQty, DiagnosticStatus, Notes
)
SELECT
      6
    , 'Orphan supply required quantity'
    , 'FAIL'
    , CONCAT('NG=', ISNULL(COMP_NET_GRP_ID, '<NULL>'), '|SRC=ORPHAN_SUPPLY')
    , COMP_NET_GRP_ID, DBG_Explosion_Source, COUNT(*)
    , SUM(CAST(COALESCE([Line Qty. Required], 0) AS decimal(38, 8)))
    , SUM(CAST(COALESCE([Line Qty. Available], 0) AS decimal(38, 8)))
    , 'ORPHAN_SUPPLY has required qty'
    , 'Orphan supply should have required qty = 0.'
FROM MPM_DWH.dbo.MRP_V4
WHERE COMP_NET_GRP_ID = @NetGrp AND DBG_Explosion_Source = 'ORPHAN_SUPPLY'
GROUP BY COMP_NET_GRP_ID, DBG_Explosion_Source
HAVING ABS(SUM(CAST(COALESCE([Line Qty. Required], 0) AS decimal(38, 8)))) > 0.0001;

-- 7. C/L MO status checks
INSERT INTO #Diagnostics
(
      DiagnosticNo, DiagnosticName, Severity, FailureKey, ASY_ORD, ORD_ID, COMP_PART_KEY,
      COMP_NET_GRP_ID, DBG_Explosion_Source, RowCnt, RequiredQty, AvailableQty,
      DiagnosticStatus, Notes
)
SELECT
      7
    , 'C/L MO appears as ORD_ID'
    , 'FAIL'
    , CONCAT('ORD_ID=', M.ORD_ID, '|STATUS=', MH.S_MO_STATUS_CD, '|SRC=', ISNULL(M.DBG_Explosion_Source, '<NULL>'))
    , M.ASY_ORD, M.ORD_ID, M.COMP_PART_KEY, M.COMP_NET_GRP_ID, M.DBG_Explosion_Source
    , COUNT(*)
    , SUM(CAST(COALESCE(M.[Line Qty. Required], 0) AS decimal(38, 8)))
    , SUM(CAST(COALESCE(M.[Line Qty. Available], 0) AS decimal(38, 8)))
    , 'Completed/cancelled MO appears as assigned/order supply'
    , 'C = Completed and L = Closed/Cancelled should not be active scheduled MO supply.'
FROM MPM_DWH.dbo.MRP_V4 AS M
INNER JOIN MFG_Staging.cp.MO_HDR AS MH ON MH.MO_ID = M.ORD_ID
WHERE M.COMP_NET_GRP_ID = @NetGrp AND MH.S_MO_STATUS_CD IN ('C', 'L')
GROUP BY M.ASY_ORD, M.ORD_ID, M.COMP_PART_KEY, M.COMP_NET_GRP_ID, M.DBG_Explosion_Source, MH.S_MO_STATUS_CD;

INSERT INTO #Diagnostics
(
      DiagnosticNo, DiagnosticName, Severity, FailureKey, ASY_ORD, ORD_ID, COMP_PART_KEY,
      COMP_NET_GRP_ID, DBG_Explosion_Source, RowCnt, RequiredQty, AvailableQty,
      DiagnosticStatus, Notes
)
SELECT
      7
    , 'C/L MO appears as ASY_ORD'
    , 'CHECK'
    , CONCAT('ASY_ORD=', M.ASY_ORD, '|STATUS=', MH.S_MO_STATUS_CD, '|SRC=', ISNULL(M.DBG_Explosion_Source, '<NULL>'))
    , M.ASY_ORD, M.ORD_ID, M.COMP_PART_KEY, M.COMP_NET_GRP_ID, M.DBG_Explosion_Source
    , COUNT(*)
    , SUM(CAST(COALESCE(M.[Line Qty. Required], 0) AS decimal(38, 8)))
    , SUM(CAST(COALESCE(M.[Line Qty. Available], 0) AS decimal(38, 8)))
    , 'Completed/cancelled MO appears in branch context'
    , 'Could indicate stale branch context if ASY_ORD should only represent active MO branch.'
FROM MPM_DWH.dbo.MRP_V4 AS M
INNER JOIN MFG_Staging.cp.MO_HDR AS MH ON MH.MO_ID = M.ASY_ORD
WHERE M.COMP_NET_GRP_ID = @NetGrp AND MH.S_MO_STATUS_CD IN ('C', 'L')
GROUP BY M.ASY_ORD, M.ORD_ID, M.COMP_PART_KEY, M.COMP_NET_GRP_ID, M.DBG_Explosion_Source, MH.S_MO_STATUS_CD;

-- 8. Corrected MO residual validation
SELECT DISTINCT SL.ORIG_ORD_ID AS MO_ID
INTO #IssueHistoryMO
FROM MFG_Staging.cp.INVT_TRN AS IT
INNER JOIN MFG_Staging.cp.INVT_TRN_LN AS ITL ON IT.INVT_TRN_ID = ITL.INVT_TRN_ID
LEFT JOIN MFG_Staging.cp.INVT_TRN_LN_SR_LT AS ITSL
    ON ITL.WHSE_ID = ITSL.WHSE_ID
   AND ITL.INVT_TRN_ID = ITSL.INVT_TRN_ID
   AND ITL.INVT_TRN_LN_KEY = ITSL.INVT_TRN_LN_KEY
   AND ITL.S_INVT_TRN_TYPE = ITSL.S_INVT_TRN_TYPE
   AND ITL.PART_KEY = ITSL.PART_KEY
LEFT JOIN MFG_Staging.cp.SERIAL_LOT AS SL ON ITSL.SERIAL_LOT_KEY = SL.SERIAL_LOT_KEY
WHERE IT.S_INVT_TRN_TYPE = 'I'
  AND (-1 * ITL.TRN_QTY) > 0
  AND IT.RES_ID IS NOT NULL
  AND SL.ORIG_ORD_ID IS NOT NULL;

SELECT
      MO_HDR.MO_ID AS ORD_ID
    , MO_HDR.BUILD_PART_KEY AS COMP_PART_KEY
    , INVT_PROJ.NET_GRP_ID AS COMP_NET_GRP_ID
    , MO_HDR.S_MO_STATUS_CD
    , SUM(CAST(COALESCE(MO_ALLOCATIONS.BUILD_QTY, MO_HDR.BUILD_QTY) AS decimal(38, 8))) AS OriginalMOQty
INTO #OriginalMO
FROM MFG_Staging.cp.MO_HDR AS MO_HDR
LEFT JOIN MFG_Staging.cp.MO_ALLOCATIONS AS MO_ALLOCATIONS
    ON MO_ALLOCATIONS.MO_ID = MO_HDR.MO_ID AND COALESCE(MO_ALLOCATIONS.BUILD_QTY, 0) <> 0
LEFT JOIN MFG_Staging.cp.INVT_PROJ AS INVT_PROJ
    ON INVT_PROJ.PROJ_ID = COALESCE(MO_ALLOCATIONS.BLD_PROJ_ID, MO_HDR.BLD_PROJ_ID)
LEFT JOIN #IssueHistoryMO AS IHM ON IHM.MO_ID = MO_HDR.MO_ID
WHERE MO_HDR.S_MO_STATUS_CD NOT IN ('C', 'L')
  AND COALESCE(MO_ALLOCATIONS.BUILD_QTY, MO_HDR.BUILD_QTY) > 0
  AND IHM.MO_ID IS NULL
  AND INVT_PROJ.NET_GRP_ID = @NetGrp
GROUP BY MO_HDR.MO_ID, MO_HDR.BUILD_PART_KEY, INVT_PROJ.NET_GRP_ID, MO_HDR.S_MO_STATUS_CD;

SELECT
      M.ORD_ID, M.COMP_PART_KEY, M.COMP_NET_GRP_ID
    , SUM(CAST(COALESCE(M.[Line Qty. Available], 0) AS decimal(38, 8))) AS AssignedAvailQty
    , COUNT(*) AS AssignedRows
INTO #AssignedMO
FROM MPM_DWH.dbo.MRP_V4 AS M
INNER JOIN MFG_Staging.cp.MO_HDR AS MH ON MH.MO_ID = M.ORD_ID
WHERE M.COMP_NET_GRP_ID = @NetGrp
  AND ISNULL(M.DBG_Explosion_Source, '') <> 'ORPHAN_SUPPLY'
GROUP BY M.ORD_ID, M.COMP_PART_KEY, M.COMP_NET_GRP_ID;

SELECT
      M.ORD_ID, M.COMP_PART_KEY, M.COMP_NET_GRP_ID
    , SUM(CAST(COALESCE(M.[Line Qty. Available], 0) AS decimal(38, 8))) AS OrphanAvailQty
    , COUNT(*) AS OrphanRows
INTO #OrphanMO
FROM MPM_DWH.dbo.MRP_V4 AS M
INNER JOIN MFG_Staging.cp.MO_HDR AS MH ON MH.MO_ID = M.ORD_ID
WHERE M.COMP_NET_GRP_ID = @NetGrp
  AND M.DBG_Explosion_Source = 'ORPHAN_SUPPLY'
GROUP BY M.ORD_ID, M.COMP_PART_KEY, M.COMP_NET_GRP_ID;

SELECT
      COALESCE(O.ORD_ID, A.ORD_ID, R.ORD_ID) AS ORD_ID
    , COALESCE(O.COMP_PART_KEY, A.COMP_PART_KEY, R.COMP_PART_KEY) AS COMP_PART_KEY
    , COALESCE(O.COMP_NET_GRP_ID, A.COMP_NET_GRP_ID, R.COMP_NET_GRP_ID) AS COMP_NET_GRP_ID
    , O.S_MO_STATUS_CD
    , COALESCE(O.OriginalMOQty, 0) AS OriginalMOQty
    , COALESCE(A.AssignedAvailQty, 0) AS AssignedAvailQty
    , COALESCE(R.OrphanAvailQty, 0) AS OrphanAvailQty
    , COALESCE(A.AssignedRows, 0) AS AssignedRows
    , COALESCE(R.OrphanRows, 0) AS OrphanRows
INTO #CombinedMO
FROM #OriginalMO AS O
FULL OUTER JOIN #AssignedMO AS A
    ON A.ORD_ID = O.ORD_ID
   AND A.COMP_PART_KEY = O.COMP_PART_KEY
   AND ISNULL(A.COMP_NET_GRP_ID, '<NULL>') = ISNULL(O.COMP_NET_GRP_ID, '<NULL>')
FULL OUTER JOIN #OrphanMO AS R
    ON R.ORD_ID = COALESCE(O.ORD_ID, A.ORD_ID)
   AND R.COMP_PART_KEY = COALESCE(O.COMP_PART_KEY, A.COMP_PART_KEY)
   AND ISNULL(R.COMP_NET_GRP_ID, '<NULL>') = ISNULL(COALESCE(O.COMP_NET_GRP_ID, A.COMP_NET_GRP_ID), '<NULL>');

INSERT INTO #Diagnostics
(
      DiagnosticNo, DiagnosticName, Severity, FailureKey, ORD_ID, COMP_PART_KEY,
      COMP_NET_GRP_ID, RowCnt, OriginalQty, AssignedQty, OrphanQty, ExpectedQty,
      ResidualDelta, DiagnosticStatus, Notes
)
SELECT
      8
    , 'Corrected MO residual validation'
    , 'FAIL'
    , CONCAT('ORD_ID=', ORD_ID, '|PART=', COMP_PART_KEY, '|NG=', ISNULL(COMP_NET_GRP_ID, '<NULL>'))
    , ORD_ID, COMP_PART_KEY, COMP_NET_GRP_ID
    , AssignedRows + OrphanRows
    , OriginalMOQty
    , AssignedAvailQty
    , OrphanAvailQty
    , OriginalMOQty - AssignedAvailQty
    , OrphanAvailQty - (OriginalMOQty - AssignedAvailQty)
    , CASE
          WHEN OriginalMOQty = 0 AND AssignedAvailQty > 0 THEN 'Assigned MO has no matching active original MO supply grain'
          WHEN AssignedAvailQty > OriginalMOQty + 0.0001 THEN 'Assigned quantity exceeds active original MO supply'
          WHEN ABS(OrphanAvailQty - (OriginalMOQty - AssignedAvailQty)) > 0.0001 THEN 'MO orphan residual mismatch'
          ELSE 'OK'
      END
    , CONCAT('OriginalMOQty=', OriginalMOQty, '; AssignedAvailQty=', AssignedAvailQty,
             '; OrphanAvailQty=', OrphanAvailQty, '; ExpectedOrphanQty=', OriginalMOQty - AssignedAvailQty,
             '; AssignedRows=', AssignedRows, '; OrphanRows=', OrphanRows)
FROM #CombinedMO
WHERE OriginalMOQty = 0 AND AssignedAvailQty > 0
   OR AssignedAvailQty > OriginalMOQty + 0.0001
   OR ABS(OrphanAvailQty - (OriginalMOQty - AssignedAvailQty)) > 0.0001;

-- 9. Seed top-level quantity preservation
SELECT
      RES_ID, RES_LN_NO, RES_PART_KEY
    , MAX(CAST(COALESCE(RES_PART_QTY, 0) AS decimal(38, 8))) AS RES_PART_QTY
    , SUM(CAST(COALESCE([Line Qty. Required], 0) AS decimal(38, 8))) AS TopLevelRequiredQty
    , COUNT(*) AS TopLevelRows
INTO #SeedTopLevel
FROM MPM_DWH.dbo.MRP_V4
WHERE COMP_NET_GRP_ID = @NetGrp
  AND ISNULL(DBG_Explosion_Source, '') <> 'ORPHAN_SUPPLY'
  AND BOM_LVL = 1
  AND RES_PART_KEY = COMP_PART_KEY
GROUP BY RES_ID, RES_LN_NO, RES_PART_KEY;

INSERT INTO #Diagnostics
(
      DiagnosticNo, DiagnosticName, Severity, FailureKey, RES_ID, RES_LN_NO,
      COMP_PART_KEY, RowCnt, RequiredQty, ExpectedQty, ResidualDelta,
      DiagnosticStatus, Notes
)
SELECT
      9
    , 'Seed top-level quantity preservation'
    , 'FAIL'
    , CONCAT('RES=', RES_ID, '|LN=', RES_LN_NO, '|RES_PART_KEY=', RES_PART_KEY)
    , RES_ID, RES_LN_NO, RES_PART_KEY
    , TopLevelRows
    , TopLevelRequiredQty
    , RES_PART_QTY
    , TopLevelRequiredQty - RES_PART_QTY
    , 'Top-level required qty does not equal reservation part qty'
    , CONCAT('RES_PART_QTY=', RES_PART_QTY, '; TopLevelRequiredQty=', TopLevelRequiredQty)
FROM #SeedTopLevel
WHERE ABS(TopLevelRequiredQty - RES_PART_QTY) > 0.0001;

-- 10. Covered parent should not have descendants
SELECT
      P.RES_ID, P.RES_LN_NO, P.BOM_LVL AS ParentBOMLVL, P.MRP_NEED_DATE AS ParentMRPNeedDate
    , P.ASY_ORD AS ParentASYORD, P.COMP_PART_KEY AS ParentCOMPPartKey, P.COMP_NET_GRP_ID
    , P.ORD_ID AS ParentORDID, P.DBG_Explosion_Source AS ParentSource
    , COUNT(*) AS DescendantRows
    , SUM(CASE WHEN C.DBG_Explosion_Source LIKE 'MBOM%' THEN 1 ELSE 0 END) AS MBOMDescendantRows
    , SUM(CASE WHEN C.DBG_Explosion_Source LIKE 'MO_RQMT%' THEN 1 ELSE 0 END) AS MORQMTDescendantRows
    , MIN(C.BOM_LVL) AS MinChildBOMLVL
    , MAX(C.BOM_LVL) AS MaxChildBOMLVL
INTO #CoveredParentDesc
FROM MPM_DWH.dbo.MRP_V4 AS P
INNER JOIN MPM_DWH.dbo.MRP_V4 AS C
    ON C.COMP_NET_GRP_ID = P.COMP_NET_GRP_ID
   AND C.RES_ID = P.RES_ID
   AND C.RES_LN_NO = P.RES_LN_NO
   AND C.PATH_STRING IS NOT NULL
   AND P.PATH_STRING IS NOT NULL
   AND C.PATH_STRING <> P.PATH_STRING
   AND C.PATH_STRING LIKE P.PATH_STRING + '%'
WHERE P.COMP_NET_GRP_ID = @NetGrp
  AND P.DBG_Explosion_Source IN ('COVERED_ISSUED', 'COVERED_HARD_PEGGED_INV', 'COVERED_GENERAL_INV', 'COVERED_PO', 'COVERED_PR', 'COVERED_PLO')
  AND ISNULL(C.DBG_Explosion_Source, '') <> 'ORPHAN_SUPPLY'
GROUP BY P.RES_ID, P.RES_LN_NO, P.BOM_LVL, P.MRP_NEED_DATE, P.ASY_ORD,
         P.COMP_PART_KEY, P.COMP_NET_GRP_ID, P.ORD_ID, P.DBG_Explosion_Source;

INSERT INTO #Diagnostics
(
      DiagnosticNo, DiagnosticName, Severity, FailureKey, RES_ID, RES_LN_NO, BOM_LVL,
      MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY, COMP_NET_GRP_ID, ORD_ID,
      DBG_Explosion_Source, RowCnt, DiagnosticStatus, Notes
)
SELECT TOP (200)
      10
    , 'Covered parent has descendants'
    , 'FAIL'
    , CONCAT('RES=', RES_ID, '|LN=', RES_LN_NO, '|PARENT_LVL=', ParentBOMLVL, '|PART=', ParentCOMPPartKey, '|SRC=', ParentSource)
    , RES_ID, RES_LN_NO, ParentBOMLVL, ParentMRPNeedDate, ParentASYORD,
      ParentCOMPPartKey, COMP_NET_GRP_ID, ParentORDID, ParentSource
    , DescendantRows
    , 'Covered finished/procurement parent has child demand below it'
    , CONCAT('DescendantRows=', DescendantRows, '; MBOMDescendantRows=', MBOMDescendantRows,
             '; MORQMTDescendantRows=', MORQMTDescendantRows, '; ChildLevelRange=', MinChildBOMLVL, '-', MaxChildBOMLVL)
FROM #CoveredParentDesc
ORDER BY DescendantRows DESC, RES_ID, RES_LN_NO, ParentBOMLVL;

-- 11. MO parent child-source behavior
SELECT
      P.RES_ID, P.RES_LN_NO, P.BOM_LVL AS ParentBOMLVL, P.MRP_NEED_DATE AS ParentMRPNeedDate
    , P.ASY_ORD AS ParentASYORD, P.COMP_PART_KEY AS ParentCOMPPartKey, P.COMP_NET_GRP_ID
    , P.ORD_ID AS ParentORDID
    , COUNT(*) AS DescendantRows
    , SUM(CASE WHEN C.DBG_Explosion_Source LIKE 'MO_RQMT%' THEN 1 ELSE 0 END) AS MORQMTDescendantRows
    , SUM(CASE WHEN C.DBG_Explosion_Source = 'MBOM' THEN 1 ELSE 0 END) AS GenericMBOMDescendantRows
    , SUM(CASE WHEN C.DBG_Explosion_Source = 'MBOM_FALLBACK_FROM_MO' THEN 1 ELSE 0 END) AS FallbackMBOMDescendantRows
INTO #MOParentDesc
FROM MPM_DWH.dbo.MRP_V4 AS P
LEFT JOIN MPM_DWH.dbo.MRP_V4 AS C
    ON C.COMP_NET_GRP_ID = P.COMP_NET_GRP_ID
   AND C.RES_ID = P.RES_ID
   AND C.RES_LN_NO = P.RES_LN_NO
   AND C.PATH_STRING IS NOT NULL
   AND P.PATH_STRING IS NOT NULL
   AND C.PATH_STRING <> P.PATH_STRING
   AND C.PATH_STRING LIKE P.PATH_STRING + '%'
   AND ISNULL(C.DBG_Explosion_Source, '') <> 'ORPHAN_SUPPLY'
WHERE P.COMP_NET_GRP_ID = @NetGrp
  AND P.DBG_Explosion_Source = 'MO_MATCHED_PARENT'
GROUP BY P.RES_ID, P.RES_LN_NO, P.BOM_LVL, P.MRP_NEED_DATE, P.ASY_ORD,
         P.COMP_PART_KEY, P.COMP_NET_GRP_ID, P.ORD_ID;

INSERT INTO #Diagnostics
(
      DiagnosticNo, DiagnosticName, Severity, FailureKey, RES_ID, RES_LN_NO, BOM_LVL,
      MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY, COMP_NET_GRP_ID, ORD_ID,
      DBG_Explosion_Source, RowCnt, DiagnosticStatus, Notes
)
SELECT TOP (200)
      11
    , 'MO parent has generic MBOM descendants'
    , 'FAIL'
    , CONCAT('RES=', RES_ID, '|LN=', RES_LN_NO, '|MO=', ParentORDID, '|PART=', ParentCOMPPartKey)
    , RES_ID, RES_LN_NO, ParentBOMLVL, ParentMRPNeedDate, ParentASYORD,
      ParentCOMPPartKey, COMP_NET_GRP_ID, ParentORDID, 'MO_MATCHED_PARENT'
    , GenericMBOMDescendantRows
    , 'MO-covered parent has generic MBOM descendants'
    , CONCAT('MORQMTDescendantRows=', MORQMTDescendantRows, '; GenericMBOMDescendantRows=', GenericMBOMDescendantRows,
             '; FallbackMBOMDescendantRows=', FallbackMBOMDescendantRows)
FROM #MOParentDesc
WHERE GenericMBOMDescendantRows > 0
ORDER BY GenericMBOMDescendantRows DESC;

INSERT INTO #Diagnostics
(
      DiagnosticNo, DiagnosticName, Severity, FailureKey, RES_ID, RES_LN_NO, BOM_LVL,
      MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY, COMP_NET_GRP_ID, ORD_ID,
      DBG_Explosion_Source, RowCnt, DiagnosticStatus, Notes
)
SELECT TOP (200)
      11
    , 'MO parent has no MO_RQMT descendants'
    , 'CHECK'
    , CONCAT('RES=', RES_ID, '|LN=', RES_LN_NO, '|MO=', ParentORDID, '|PART=', ParentCOMPPartKey)
    , RES_ID, RES_LN_NO, ParentBOMLVL, ParentMRPNeedDate, ParentASYORD,
      ParentCOMPPartKey, COMP_NET_GRP_ID, ParentORDID, 'MO_MATCHED_PARENT'
    , DescendantRows
    , 'MO-covered parent has no MO_RQMT descendants'
    , 'May be valid if MO has no requirements, but should be spot-checked.'
FROM #MOParentDesc
WHERE MORQMTDescendantRows = 0
ORDER BY DescendantRows DESC, RES_ID, RES_LN_NO;

-- 12. Exact duplicate MO_MATCHED_PARENT
INSERT INTO #Diagnostics
(
      DiagnosticNo, DiagnosticName, Severity, FailureKey, RES_ID, RES_LN_NO, BOM_LVL,
      MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY, COMP_NET_GRP_ID, ORD_ID,
      DBG_Explosion_Source, DBG_Matched_MO_ID, RowCnt, RequiredQty, AvailableQty,
      DiagnosticStatus, Notes
)
SELECT
      12
    , 'Exact duplicate MO_MATCHED_PARENT'
    , 'FAIL'
    , CONCAT('RES=', RES_ID, '|LN=', RES_LN_NO, '|PART=', COMP_PART_KEY, '|ORD=', ORD_ID)
    , RES_ID, RES_LN_NO, BOM_LVL, MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY, COMP_NET_GRP_ID
    , ORD_ID, DBG_Explosion_Source, DBG_Matched_MO_ID
    , COUNT(*)
    , SUM(CAST(COALESCE([Line Qty. Required], 0) AS decimal(38, 8)))
    , SUM(CAST(COALESCE([Line Qty. Available], 0) AS decimal(38, 8)))
    , 'Exact duplicate MO_MATCHED_PARENT survived final output'
    , 'Expected blank after duplicate pruning and final reporting-grain collapse.'
FROM MPM_DWH.dbo.MRP_V4
WHERE COMP_NET_GRP_ID = @NetGrp
  AND DBG_Explosion_Source = 'MO_MATCHED_PARENT'
GROUP BY RES_ID, RES_LN_NO, BOM_LVL, MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY,
         COMP_NET_GRP_ID, ORD_ID, DBG_Explosion_Source, DBG_Matched_MO_ID
HAVING COUNT(*) > 1;

-- 13. Null net group on non-orphan rows
INSERT INTO #Diagnostics
(
      DiagnosticNo, DiagnosticName, Severity, FailureKey, RES_ID, RES_LN_NO, BOM_LVL,
      MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY, COMP_NET_GRP_ID, ORD_ID,
      DBG_Explosion_Source, RowCnt, RequiredQty, AvailableQty, DiagnosticStatus, Notes
)
SELECT
      13
    , 'Null net group on non-orphan row'
    , 'FAIL'
    , CONCAT('RES=', ISNULL(RES_ID, '<NULL>'), '|LN=', ISNULL(CONVERT(varchar(20), RES_LN_NO), '<NULL>'), '|PART=', ISNULL(CONVERT(varchar(50), COMP_PART_KEY), '<NULL>'))
    , RES_ID, RES_LN_NO, BOM_LVL, MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY, COMP_NET_GRP_ID
    , ORD_ID, DBG_Explosion_Source, COUNT(*)
    , SUM(CAST(COALESCE([Line Qty. Required], 0) AS decimal(38, 8)))
    , SUM(CAST(COALESCE([Line Qty. Available], 0) AS decimal(38, 8)))
    , 'Non-orphan row has null net group'
    , 'Net group match is a hard requirement.'
FROM MPM_DWH.dbo.MRP_V4
WHERE ISNULL(DBG_Explosion_Source, '') <> 'ORPHAN_SUPPLY'
  AND COMP_NET_GRP_ID IS NULL
GROUP BY RES_ID, RES_LN_NO, BOM_LVL, MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY,
         COMP_NET_GRP_ID, ORD_ID, DBG_Explosion_Source;

-- PASS row if no fail/check rows exist
IF NOT EXISTS (SELECT 1 FROM #Diagnostics WHERE Severity IN ('FAIL', 'CHECK'))
BEGIN
    INSERT INTO #Diagnostics
    (
          DiagnosticNo, DiagnosticName, Severity, FailureKey, DiagnosticStatus, Notes
    )
    VALUES
    (
          999
        , 'V4 one-net-group validation'
        , 'PASS'
        , 'NO_FAILURES'
        , 'All V4 validation checks returned clean'
        , 'Reviewed source profile, blank source, qty sanity, fragments, orphan scope, C/L MOs, corrected MO residuals, seed preservation, parent suppression, and MO child-source behavior.'
    );
END;

SELECT
      DiagnosticNo, DiagnosticName, Severity, FailureKey, RES_ID, RES_LN_NO,
      BOM_LVL, MRP_NEED_DATE, ASY_ORD, COMP_PART_KEY, COMP_NET_GRP_ID,
      ORD_ID, DBG_Explosion_Source, DBG_Matched_MO_ID, RowCnt, RequiredQty,
      AvailableQty, ExtraQty, OriginalQty, AssignedQty, OrphanQty, ExpectedQty,
      ResidualDelta, DiagnosticStatus, Notes
FROM #Diagnostics
WHERE Severity IN ('FAIL', 'CHECK', 'PASS', 'INFO')
ORDER BY
      CASE Severity WHEN 'FAIL' THEN 1 WHEN 'CHECK' THEN 2 WHEN 'PASS' THEN 3 WHEN 'INFO' THEN 4 ELSE 5 END
    , DiagnosticNo
    , ABS(COALESCE(ResidualDelta, ExtraQty, 0)) DESC
    , COMP_NET_GRP_ID, RES_ID, RES_LN_NO, BOM_LVL, MRP_NEED_DATE, COMP_PART_KEY, ORD_ID;
"""


def _run_v4_post_write_diagnostics(engine, net_grp='ANA_01F'):
    sql_text = _build_v4_post_write_diagnostic_sql(net_grp=net_grp)
    diagnostics_df = _fetch_sql_batch_as_dataframe(engine, sql_text)
    diagnostics_text = _format_dataframe_for_llm(diagnostics_df, max_rows=1000)
    fail_check_count = 0
    if diagnostics_df is not None and not diagnostics_df.empty and 'Severity' in diagnostics_df.columns:
        fail_check_count = int(diagnostics_df['Severity'].isin(['FAIL', 'CHECK']).sum())
    _progress(
        "Post-write V4 diagnostics complete",
        diagnostic_rows=_row_count(diagnostics_df),
        fail_check_rows=fail_check_count
    )
    return diagnostics_text


def _build_llm_clipboard_package(status, diagnostics_text='', error_text=''):
    ended_at = datetime.datetime.now()
    elapsed_min = (ended_at - start_time).total_seconds() / 60
    run_output_text = '\n'.join(RUN_OUTPUT_LINES) if RUN_OUTPUT_LINES else '<no captured print output>'

    sections = [
        '# MRP V4 Script Run Package',
        '',
        f'Status: {status}',
        f'Started: {start_time:%Y-%m-%d %H:%M:%S}',
        f'Ended: {ended_at:%Y-%m-%d %H:%M:%S}',
        f'Elapsed minutes: {elapsed_min:.2f}',
        'Output table: MPM_DWH.dbo.MRP_V4',
        '',
        '## Captured script output / print log',
        '```text',
        run_output_text,
        '```',
    ]

    if diagnostics_text:
        sections.extend([
            '',
            '## Post-write SQL diagnostics for LLM review',
            '```tsv',
            diagnostics_text,
            '```',
        ])

    if error_text:
        sections.extend([
            '',
            '## Script error / traceback',
            '```text',
            error_text,
            '```',
        ])

    sections.extend([
        '',
        '## LLM review request',
        'Please analyze this MRP V4 run log and SQL diagnostic output. Focus on FAIL/CHECK diagnostics first, then summarize whether MRP_V4 is clean for the target netting group and what should be patched next if anything failed.'
    ])
    return '\n'.join(sections)


def _copy_llm_package_to_clipboard(status, diagnostics_text='', error_text=''):
    package = _build_llm_clipboard_package(
        status=status,
        diagnostics_text=diagnostics_text,
        error_text=error_text
    )
    if pyperclip is None:
        _progress("pyperclip unavailable; writing LLM package to local text file instead")
        fallback_path = 'MRP_V4_LLM_Run_Package.txt'
        with open(fallback_path, 'w', encoding='utf-8') as f:
            f.write(package)
        _progress("LLM package written to fallback text file", path=fallback_path, chars=len(package))
        return False

    pyperclip.copy(package)
    _progress("Copied full run output and diagnostics to clipboard", chars=len(package))
    return True


